export default function NavBar() {
  const containerRef = useRef(null)
  const [scale, setScale] = useState(1)
  const [hoveredLink, setHoveredLink] = useState(null)

  useEffect(() => {
    const el = containerRef.current
    if (!el) return
    const observer = new ResizeObserver(entries => {
      setScale(entries[0].contentRect.width / 1905)
    })
    observer.observe(el)
    return () => observer.disconnect()
  }, [])

  return (
    <nav
      ref={containerRef}
      style={{
        position: 'fixed',
        top: 0,
        left: 0,
        right: 0,
        zIndex: 50,
        height: 77 * scale,
        overflow: 'hidden',
        backdropFilter: 'blur(10px)',
        WebkitBackdropFilter: 'blur(10px)',
      }}
    >
      <div
        style={{
          width: 1905,
          height: 77,
          transformOrigin: 'top left',
          transform: `scale(${scale})`,
          position: 'relative',
        }}
      >
        <svg
          width="1905"
          height="77"
          viewBox="0 0 1905 77"
          fill="none"
          xmlns="http://www.w3.org/2000/svg"
          style={{ position: 'absolute', inset: 0 }}
        >
          <path d="M0 0H1905V77H0V0Z" fill="#0A0A08" fillOpacity="0.85" />
          <line x1="0" y1="76.5" x2="1905" y2="76.5" stroke="rgba(201,168,76,0.15)" strokeWidth="1" />
          {LOGO_PATHS.map((d, i) => (
            <path key={i} d={d} fill="white" />
          ))}
          <path d={SLASH_PATH} fill="white" />
          <path d={TAGLINE_PATH} fill="white" />
          {NAV_LINK_PATHS.map((d, i) => (
            <g
              key={i}
              style={{ cursor: 'pointer' }}
              onMouseEnter={() => setHoveredLink(i)}
              onMouseLeave={() => setHoveredLink(null)}
              onClick={() => {
                const el = document.querySelector(NAV_LINKS[i].href)
                el?.scrollIntoView({ behavior: 'smooth' })
              }}
            >
              <path
                d={d}
                fill={hoveredLink === i ? '#C9A84C' : '#F5F2EC'}
                style={{ transition: 'fill 0.2s ease' }}
              />
              <rect
                x={NAV_LINKS[i].x}
                y={25}
                width={NAV_LINKS[i].width}
                height={30}
                fill="transparent"
              />
            </g>
          ))}
        </svg>
      </div>
    </nav>
  )
}
